param([string]$OutputDir="backups")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Force $OutputDir|Out-Null;$stamp=Get-Date -Format 'yyyyMMdd-HHmmss';$file=Join-Path $OutputDir "chronicle-$stamp.sql.gz";docker compose exec -T postgres sh -c 'pg_dump -U chronicle -d chronicle --clean --if-exists | gzip -c > /tmp/chronicle.sql.gz';if($LASTEXITCODE){throw 'pg_dump failed'};docker compose cp postgres:/tmp/chronicle.sql.gz $file;if($LASTEXITCODE-or!(Test-Path $file)){throw 'Backup copy failed'};docker compose exec -T postgres rm -f /tmp/chronicle.sql.gz|Out-Null;Write-Output (Resolve-Path $file)
